// turn any instagram post/reel URL into its bare embeddable iframe src
function igEmbedSrc(url) {
  if (!url) return null;
  const m = url.match(/instagram\.com\/(p|reel|tv)\/([A-Za-z0-9_-]+)/);
  if (!m) return null;
  return `https://www.instagram.com/${m[1]}/${m[2]}/embed`;
}

// extract @handle from an instagram profile URL
function igHandle(url) {
  if (!url) return null;
  const m = url.match(/instagram\.com\/([A-Za-z0-9_.]+)/);
  if (!m) return null;
  const h = m[1];
  // ignore post/reel paths
  if (["p", "reel", "reels", "tv", "stories", "explore"].includes(h)) return null;
  return "@" + h;
}

// normalize an item's images into an array (supports legacy single `image`)
function itemImages(i) {
  if (Array.isArray(i.images) && i.images.length) return i.images;
  if (i.image) return [i.image];
  return [];
}

// normalize an item's source links: supports a `sources` array [{label,url}] or a single `link`
function itemSources(i) {
  if (Array.isArray(i.sources) && i.sources.length) {
    return i.sources.map((s) => (typeof s === "string" ? { url: s, label: "" } : s)).filter((s) => s.url);
  }
  if (i.link) return [{ url: i.link, label: "Open original" }];
  return [];
}

// figure out the reference format: explicit field wins, else infer
function itemFormat(i) {
  if (i.format) return i.format;
  if (i.link && /instagram\.com\/(reel|tv)\//.test(i.link)) return "reel";
  if (itemImages(i).length > 1) return "carousel";
  return "static";
}
